1	import { describe, it, expect, vi, beforeEach } from "vitest";
2	import { screen, fireEvent } from "@testing-library/react";
3	import { renderWithProviders } from "./helpers";
4	import { ResolveMarketPanel } from "@/features/market/ResolveMarketPanel";
5	import type { Market } from "@/lib/api/types";
6	
7	// ---------------------------------------------------------------------------
8	// Mocks
9	// ---------------------------------------------------------------------------
10	
11	const mockMutate = vi.fn();
12	
13	vi.mock("@/features/session/context", async () => {
14	  const actual = await vi.importActual<typeof import("@/features/session/context")>(
15	    "@/features/session/context",
16	  );
17	  return {
18	    ...actual,
19	    useSession: vi.fn(),
20	  };
21	});
22	
23	vi.mock("@/lib/query/hooks", () => ({
24	  useResolveMarket: vi.fn(),
25	}));
26	
27	import { useSession } from "@/features/session/context";
28	import { useResolveMarket } from "@/lib/query/hooks";
29	
30	const mockUseSession = vi.mocked(useSession);
31	const mockUseResolveMarket = vi.mocked(useResolveMarket);
32	
33	// ---------------------------------------------------------------------------
34	// Fixtures
35	// ---------------------------------------------------------------------------
36	
37	const mockMarket: Market = {
38	  id: "mkt-1",
39	  title: "Will it rain tomorrow?",
40	  description: "Rain forecast market",
41	  variableId: "var-1",
42	  status: "active",
43	  outcomes: [
44	    { id: "out-yes", name: "Yes" },
45	    { id: "out-no", name: "No" },
46	  ],
47	  marginals: { "out-yes": 0.65, "out-no": 0.35 },
48	  liquidity: 1000,
49	  volume: 500,
50	  created_at: "2026-01-01T00:00:00Z",
51	  expires_at: "2026-12-31T00:00:00Z",
52	};
53	
54	const configuredSession = {
55	  session: { accountId: "acc-123", agentId: "agent-1" },
56	  setAccountId: vi.fn(),
57	  setAgentId: vi.fn(),
58	  isConfigured: true,
59	};
60	
61	const unconfiguredSession = {
62	  session: { accountId: "", agentId: "" },
63	  setAccountId: vi.fn(),
64	  setAgentId: vi.fn(),
65	  isConfigured: false,
66	};
67	
68	function defaultMutationState(overrides: Record<string, unknown> = {}) {
69	  return {
70	    mutate: mockMutate,
71	    mutateAsync: vi.fn(),
72	    reset: vi.fn(),
73	    isPending: false,
74	    isSuccess: false,
75	    isError: false,
76	    isIdle: true,
77	    status: "idle" as const,
78	    data: undefined,
79	    error: null,
80	    variables: undefined,
81	    failureCount: 0,
82	    failureReason: null,
83	    submittedAt: 0,
84	    context: undefined,
85	    ...overrides,
86	  } as unknown as ReturnType<typeof useResolveMarket>;
87	}
88	
89	// ---------------------------------------------------------------------------
90	// Setup
91	// ---------------------------------------------------------------------------
92	
93	beforeEach(() => {
94	  vi.clearAllMocks();
95	  mockUseSession.mockReturnValue(configuredSession);
96	  mockUseResolveMarket.mockReturnValue(defaultMutationState());
97	});
98	
99	// ---------------------------------------------------------------------------
100	// Tests
101	// ---------------------------------------------------------------------------
102	
103	describe("ResolveMarketPanel", () => {
104	  // -------------------------------------------------------------------------
105	  // Guard clause tests
106	  // -------------------------------------------------------------------------
107	
108	  describe("guard clauses", () => {
109	    it("shows resolved summary with resolution string", () => {
110	      const resolved: Market = { ...mockMarket, status: "resolved", resolution: "Yes" };
111	      renderWithProviders(<ResolveMarketPanel market={resolved} />);
112	
113	      expect(screen.getByText("Resolved")).toBeInTheDocument();
114	      expect(screen.getByText(/Outcome: Yes/)).toBeInTheDocument();
115	    });
116	
117	    it("shows resolved summary with resolutionProbabilities", () => {
118	      const resolved: Market = {
119	        ...mockMarket,
120	        status: "resolved",
121	        resolutionProbabilities: { "out-yes": 0.7, "out-no": 0.3 },
122	      };
123	      renderWithProviders(<ResolveMarketPanel market={resolved} />);
124	
125	      expect(screen.getByText("Resolved")).toBeInTheDocument();
126	      expect(screen.getByText(/out-yes 70\.0%, out-no 30\.0%/)).toBeInTheDocument();
127	    });
128	
129	    it("shows resolved summary with neither resolution nor probabilities", () => {
130	      const resolved: Market = { ...mockMarket, status: "resolved" };
131	      renderWithProviders(<ResolveMarketPanel market={resolved} />);
132	
133	      expect(screen.getByText("Resolved")).toBeInTheDocument();
134	      expect(screen.getByText(/Resolution finalized/)).toBeInTheDocument();
135	    });
136	
137	    it("returns null for draft status market", () => {
138	      const draft: Market = { ...mockMarket, status: "draft" };
139	      const { container } = renderWithProviders(<ResolveMarketPanel market={draft} />);
140	
141	      expect(container.innerHTML).toBe("");
142	    });
143	
144	    it("returns null when no accountId", () => {
145	      mockUseSession.mockReturnValue(unconfiguredSession);
146	      const { container } = renderWithProviders(<ResolveMarketPanel market={mockMarket} />);
147	
148	      expect(container.innerHTML).toBe("");
149	    });
150	  });
151	
152	  // -------------------------------------------------------------------------
153	  // Resolve form rendering
154	  // -------------------------------------------------------------------------
155	
156	  describe("resolve form rendering", () => {
157	    it("renders heading, select with placeholder and outcome options, and disabled resolve button", () => {
158	      renderWithProviders(<ResolveMarketPanel market={mockMarket} />);
159	
160	      expect(screen.getByText("Resolve Market")).toBeInTheDocument();
161	
162	      const select = screen.getByRole("combobox");
163	      expect(select).toBeInTheDocument();
164	      expect(screen.getByText("Select winning outcome...")).toBeInTheDocument();
165	      expect(screen.getByText("Yes (out-yes)")).toBeInTheDocument();
166	      expect(screen.getByText("No (out-no)")).toBeInTheDocument();
167	
168	      const resolveBtn = screen.getByRole("button", { name: "Resolve" });
169	      expect(resolveBtn).toBeDisabled();
170	    });
171	  });
172	
173	  // -------------------------------------------------------------------------
174	  // Two-step confirmation flow
175	  // -------------------------------------------------------------------------
176	
177	  describe("two-step confirmation flow", () => {
178	    it("shows confirmation UI after selecting outcome and clicking Resolve", () => {
179	      renderWithProviders(<ResolveMarketPanel market={mockMarket} />);
180	
181	      const select = screen.getByRole("combobox");
182	      fireEvent.change(select, { target: { value: "out-yes" } });
183	
184	      const resolveBtn = screen.getByRole("button", { name: "Resolve" });
185	      fireEvent.click(resolveBtn);
186	
187	      expect(screen.getByText(/Confirm resolve to/)).toBeInTheDocument();
188	      expect(screen.getByRole("button", { name: "Yes, Resolve" })).toBeInTheDocument();
189	      expect(screen.getByRole("button", { name: "Cancel" })).toBeInTheDocument();
190	    });
191	
192	    it("calls mutation.mutate with correct payload when clicking Yes, Resolve", () => {
193	      renderWithProviders(<ResolveMarketPanel market={mockMarket} />);
194	
195	      const select = screen.getByRole("combobox");
196	      fireEvent.change(select, { target: { value: "out-yes" } });
197	
198	      fireEvent.click(screen.getByRole("button", { name: "Resolve" }));
199	      fireEvent.click(screen.getByRole("button", { name: "Yes, Resolve" }));
200	
201	      expect(mockMutate).toHaveBeenCalledTimes(1);
202	      const call = mockMutate.mock.calls[0]![0];
203	      expect(call.payload.accountId).toBe("acc-123");
204	      expect(call.payload.outcomeId).toBe("out-yes");
205	      expect(call.session).toEqual({ accountId: "acc-123", agentId: "agent-1" });
206	    });
207	
208	    it("returns to initial resolve button state when clicking Cancel", () => {
209	      renderWithProviders(<ResolveMarketPanel market={mockMarket} />);
210	
211	      const select = screen.getByRole("combobox");
212	      fireEvent.change(select, { target: { value: "out-yes" } });
213	
214	      fireEvent.click(screen.getByRole("button", { name: "Resolve" }));
215	      expect(screen.getByRole("button", { name: "Yes, Resolve" })).toBeInTheDocument();
216	
217	      fireEvent.click(screen.getByRole("button", { name: "Cancel" }));
218	
219	      expect(screen.queryByRole("button", { name: "Yes, Resolve" })).not.toBeInTheDocument();
220	      expect(screen.getByRole("button", { name: "Resolve" })).toBeInTheDocument();
221	    });
222	
223	    it("resets confirming state when changing select outcome", () => {
224	      renderWithProviders(<ResolveMarketPanel market={mockMarket} />);
225	
226	      const select = screen.getByRole("combobox");
227	      fireEvent.change(select, { target: { value: "out-yes" } });
228	
229	      fireEvent.click(screen.getByRole("button", { name: "Resolve" }));
230	      expect(screen.getByRole("button", { name: "Yes, Resolve" })).toBeInTheDocument();
231	
232	      fireEvent.change(select, { target: { value: "out-no" } });
233	
234	      expect(screen.queryByRole("button", { name: "Yes, Resolve" })).not.toBeInTheDocument();
235	      expect(screen.getByRole("button", { name: "Resolve" })).toBeInTheDocument();
236	    });
237	  });
238	
239	  // -------------------------------------------------------------------------
240	  // Mutation state tests
241	  // -------------------------------------------------------------------------
242	
243	  describe("mutation states", () => {
244	    it("disables Yes, Resolve button and shows Resolving... when isPending", () => {
245	      const { rerender } = renderWithProviders(<ResolveMarketPanel market={mockMarket} />);
246	
247	      // Enter confirming state while isPending is false
248	      const select = screen.getByRole("combobox");
249	      fireEvent.change(select, { target: { value: "out-yes" } });
250	      fireEvent.click(screen.getByRole("button", { name: "Resolve" }));
251	      expect(screen.getByRole("button", { name: "Yes, Resolve" })).toBeInTheDocument();
252	
253	      // Switch to isPending and re-render (preserves internal state)
254	      mockUseResolveMarket.mockReturnValue(
255	        defaultMutationState({ isPending: true, isIdle: false, status: "pending" }),
256	      );
257	      rerender(<ResolveMarketPanel market={mockMarket} />);
258	
259	      const btn = screen.getByRole("button", { name: "Resolving..." });
260	      expect(btn).toBeDisabled();
261	    });
262	
263	    it("shows error message when isError", () => {
264	      mockUseResolveMarket.mockReturnValue(
265	        defaultMutationState({
266	          isError: true,
267	          isIdle: false,
268	          status: "error",
269	          error: new Error("Market already resolved"),
270	        }),
271	      );
272	      renderWithProviders(<ResolveMarketPanel market={mockMarket} />);
273	
274	      expect(screen.getByText("Market already resolved")).toBeInTheDocument();
275	    });
276	
277	    it("shows success message when isSuccess", () => {
278	      mockUseResolveMarket.mockReturnValue(
279	        defaultMutationState({
280	          isSuccess: true,
281	          isIdle: false,
282	          status: "success",
283	        }),
284	      );
285	      renderWithProviders(<ResolveMarketPanel market={mockMarket} />);
286	
287	      expect(screen.getByText("Market resolved successfully.")).toBeInTheDocument();
288	    });
289	  });
290	});
